char* longestCommonPrefix(char** strs, int strsSize) {
    if (!strsSize) return "";
    char* pre = strdup(strs[0]);
    for (int i = 1; i < strsSize; i++) {
        int j = 0;
        while (pre[j] && strs[i][j] && pre[j] == strs[i][j]) j++;
        pre[j] = 0;
        if (!pre[0]) break;
    }
    return pre;
}

