class Solution {
public:
    string longestCommonPrefix(vector<string>& strs) {
        if (strs.empty()) return "";
        string pre = strs[0];
        for (int i = 1; i < (int)strs.size(); i++) {
            while (strs[i].find(pre) != 0) {
                pre.pop_back();
                if (pre.empty()) return "";
            }
        }
        return pre;
    }
};
